
const DEFAULT_APPS = ["Instagram", "YouTube", "TikTok"];
const ALL_APPS = ["Instagram","YouTube","X","TikTok","Chrome","Threads","Discord","Reddit","Netflix","KakaoTalk","Safari","Pinterest"];

function getState(){
  const saved = JSON.parse(localStorage.getItem('impulseState') || 'null');
  return {
    permissions:{usage:saved?.permissions?.usage ?? false, notifications:saved?.permissions?.notifications ?? false},
    selectedApps:Array.isArray(saved?.selectedApps) ? saved.selectedApps : [],
    schedules:saved?.schedules ?? {
      Instagram:[{id:1,start:'00:00',end:'09:00'},{id:2,start:'12:00',end:'15:00'}],
      YouTube:[{id:3,start:'23:00',end:'07:00'}],
      TikTok:[],
    },
    nextRangeId:saved?.nextRangeId ?? 4,
  };
}
function setState(next){localStorage.setItem('impulseState', JSON.stringify(next));}
function ensureAppSchedules(state, app){if(!state.schedules[app]) state.schedules[app]=[];}
function appsToConfigure(state){return state.selectedApps.length ? state.selectedApps : DEFAULT_APPS.slice();}
function queryParam(name){return new URLSearchParams(window.location.search).get(name);}
function pathTo(rel){
  const root = document.body.dataset.root || ".";
  const normalized = `${root}/${rel}`.replace(/\/+/g, "/");
  if (normalized.endsWith("/")) return `${normalized}index.html`;
  return normalized;
}
function topBar(){return `<div class="topbar"><div class="time">9:41</div><div class="battery"><div class="battery-box"><div class="battery-fill"></div></div><div class="battery-cap"></div></div></div>`;}
function phoneFrame(inner){return `<div class="phone">${topBar()}${inner}</div>`;}
function permissionCard(title, body, key, enabled, icon){return `<button type="button" class="permission-card ${enabled?'active':''}" data-action="toggle-permission" data-key="${key}"><div class="permission-head"><div class="icon-badge">${icon}</div><div class="permission-text"><div class="row-title">${title}</div><div class="row-sub">${body}</div></div><div class="check ${enabled?'checked':''}">${enabled?'✓':''}</div></div></button>`;}
function checkboxRow(label, action, checked){return `<button type="button" class="checkbox-row ${checked?'active':''}" data-action="${action}"><div class="inline-row"><div class="row-title" style="margin:0;">${label}</div><div class="check ${checked?'checked':''}">${checked?'✓':''}</div></div></button>`;}
function selectedPills(selected){return `<div class="pills"><h4>선택된 앱</h4><div class="pill-list">${selected.map(app=>`<div class="pill">${app}</div>`).join('')}</div></div>`;}
function renderAppRows(search=''){const state=getState(); const keyword=search.toLowerCase(); return ALL_APPS.filter(app=>app.toLowerCase().includes(keyword)).map(app=>{const checked=state.selectedApps.includes(app); return `<button type="button" class="app-row ${checked?'active':''}" data-action="toggle-app" data-app="${app}"><div class="check ${checked?'checked':''}">${checked?'✓':''}</div><div class="app-label"><div class="app-name">${app}</div></div></button>`;}).join('');}
function renderWelcome(){return `<div class="screen"><div class="center-fill"><div class="title-lg">안녕!</div><p class="body" style="text-align:center;max-width:220px;margin-left:auto;margin-right:auto;">무심코 폰을 켜는 순간, 잠깐 멈춰 생각할 수 있도록 도와줄게.</p><div class="box" style="height:208px;padding:16px;"><div class="placeholder">캐릭터 영역</div></div></div><div class="footer-action"><a class="primary-btn" style="display:flex;align-items:center;justify-content:center;" href="${pathTo('onboarding/permissions/')}">시작하기</a></div></div>`;}
function renderPermissions(){const state=getState(); const allAllowed=state.permissions.usage && state.permissions.notifications; return `<div class="screen"><div style="flex:1;min-height:0;display:flex;flex-direction:column;"><div class="title-lg">권한을 허용해줘</div><p class="body">필요한 권한만 간단히 설정해보자.</p><div class="stack" style="margin-bottom:12px;">${permissionCard('앱 사용 감지 권한','선택한 앱을 실행했을 때 개입','usage',state.permissions.usage,'🛡')}${permissionCard('알림 권한','멈춤 알림, 회고 알림','notifications',state.permissions.notifications,'🔔')}${checkboxRow('모두 허용하기','allow-all',allAllowed)}</div><div class="box" style="padding:14px;"><div class="small muted">현재 상태: ${state.permissions.usage ? '앱 사용 감지 허용' : '앱 사용 감지 미허용'} / ${state.permissions.notifications ? '알림 허용' : '알림 미허용'}</div></div></div><div class="footer-action"><a class="primary-btn" id="permissions-next" style="display:flex;align-items:center;justify-content:center;${allAllowed ? '' : 'pointer-events:none;opacity:.6;'}" href="${pathTo('onboarding/apps/')}">다음</a></div></div>`;}
function renderAppsPage(){const state=getState(); const selected=state.selectedApps; return `<div class="screen"><div style="flex:1;min-height:0;display:flex;flex-direction:column;"><div class="title-lg">어떤 앱을 줄이고 싶어?</div><p class="body">앱을 선택해줘.</p><div class="search-wrap"><span style="color:#a1a1aa;">⌕</span><input id="app-search" placeholder="앱 검색" /></div>${selected.length ? selectedPills(selected) : ''}<div class="scroll-box" id="app-list"></div></div><div class="footer-action"><a id="apps-complete" class="primary-btn" style="display:flex;align-items:center;justify-content:center;${selected.length ? '' : 'pointer-events:none;opacity:.6;'}" href="${pathTo('main/settings/')}">선택 완료</a></div></div>`;}
function renderSettingsList(){const state=getState(); const apps=appsToConfigure(state); const totalRanges=apps.reduce((sum, app)=>sum + (state.schedules[app]?.length || 0), 0); return `<div class="screen"><div style="flex:1;min-height:0;overflow-y:auto;"><div class="title-lg">제한 앱 설정</div><p class="body">제한하고 싶은 앱을 눌러 잠글 시간대를 설정해.</p><div class="summary-grid"><div class="summary-card"><div class="summary-label">제한 앱</div><div class="summary-value">${apps.length}개</div></div><div class="summary-card"><div class="summary-label">전체 시간대</div><div class="summary-value">${totalRanges}개</div></div></div><div class="stack">${apps.map(app=>{const ranges=state.schedules[app] || []; return `<a class="settings-row" href="${pathTo(`main/settings/detail/?app=${encodeURIComponent(app)}`)}"><div style="display:flex;align-items:center;justify-content:space-between;gap:12px;"><div><div class="app-name">${app}</div><div class="app-meta">${ranges.length ? `${ranges.length}개 시간대 설정됨` : '시간대 없음'}</div></div><div class="chevron">›</div></div></a>`;}).join('')}</div></div></div>`;}
function timeToMinutes(value){const [h,m]=value.split(':').map(Number); return h*60+m;}
function getSegments(range){const start=timeToMinutes(range.start); const end=timeToMinutes(range.end); if(Number.isNaN(start)||Number.isNaN(end)) return []; if(start===end) return [{start:0,end:1440}]; if(end>start) return [{start,end}]; return [{start,end:1440},{start:0,end}];}
function renderTimeline(ranges){const fills=ranges.flatMap(getSegments).map((seg, i)=>`<div class="timeline-fill" style="left:${(seg.start/1440)*100}%;width:${((seg.end-seg.start)/1440)*100}%;"></div>`).join(''); return `<div class="timeline-box"><div class="timeline-title">잠금 시간대</div><div class="timeline-track">${fills}</div><div class="timeline-labels"><span>00:00</span><span>06:00</span><span>12:00</span><span>18:00</span><span>24:00</span></div></div>`;}
function rangeCard(app, range, index){return `<div class="range-card" data-range-id="${range.id}"><div class="range-title">시간대 ${index+1}</div><div class="range-grid"><input type="time" data-app="${app}" data-range="${range.id}" data-field="start" value="${range.start}"><div class="muted">~</div><input type="time" data-app="${app}" data-range="${range.id}" data-field="end" value="${range.end}"></div></div>`;}
function renderSettingsDetail(){const state=getState(); const app=queryParam('app') || 'Instagram'; ensureAppSchedules(state, app); setState(state); const ranges=state.schedules[app] || []; return `<div class="screen"><div class="back-row"><a class="icon-btn" href="${pathTo('main/settings/')}">←</a><div><div class="title-lg" style="font-size:24px;margin-bottom:2px;">${app}</div><div class="small muted">잠글 시간 설정</div></div></div><div style="flex:1;min-height:0;overflow-y:auto;display:grid;gap:12px;">${renderTimeline(ranges)}<div id="range-list" class="stack">${ranges.map((range, index)=>rangeCard(app, range, index)).join('')}</div><button type="button" id="add-range" class="ghost-btn" style="display:flex;align-items:center;justify-content:center;gap:8px;"><span>＋</span><span>시간대 추가</span></button></div><div class="footer-action"><a class="primary-btn" style="display:flex;align-items:center;justify-content:center;" href="${pathTo('main/settings/')}">저장</a></div></div>`;}
function renderInterventionHome(){const state=getState(); const tappable=appsToConfigure(state); const homeApps=[...tappable, ...ALL_APPS.filter(a=>!tappable.includes(a))].slice(0,8); return `<div class="phone"><div class="home-bg"><div class="topbar" style="position:absolute;left:0;right:0;top:0;z-index:10;"><div class="time">9:41</div><div class="battery"><div class="battery-box"><div class="battery-fill"></div></div><div class="battery-cap"></div></div></div><div class="home-icons">${homeApps.map(app=>`<a class="app-icon" href="${pathTo(`main/intervention/open/?app=${encodeURIComponent(app)}`)}"><div class="app-square ${tappable.includes(app) ? 'active' : ''}">${app === 'Instagram' ? 'IG' : app.slice(0,2)}</div><div class="app-caption">${app}</div></a>`).join('')}</div></div></div>`;}
function appPreview(app){return `<div class="app-preview">${topBar()}<div class="app-top"><div class="app-top-title">${app}</div><div style="display:flex;gap:12px;color:#52525b;"><span>♡</span><span>✈</span></div></div><div style="flex:1;overflow:hidden;">${app === 'Instagram' ? `<div class="story-row">${[1,2,3,4].map(()=>`<div class="story-item"><div class="story-circle"></div><div class="story-label">story</div></div>`).join('')}</div>` : `<div class="app-placeholder"><div class="app-placeholder-inner">${app} 화면</div></div>`}</div><div class="bottom-nav"><span>⌂</span><span>⌕</span><span>＋</span><span>♡</span><span>◦</span></div></div>`;}
function interventionOverlay(){return `<div class="overlay" id="overlay"><div class="overlay-card"><div class="overlay-head"><div><div class="overlay-title">왜 켰어?</div><p class="overlay-body">지금 이 앱을 연 이유를 짧게 적어줘.</p></div><button type="button" class="icon-btn" id="close-overlay">✕</button></div><div class="overlay-textarea"><textarea id="reason-text" placeholder="예: 습관적으로 눌렀어 / DM 확인하려고 / 그냥 심심해서"></textarea></div><div class="chips">${['습관적으로 눌렀어','DM 확인하려고','새 게시물 보려고','심심해서'].map(text=>`<button type="button" class="chip" data-chip="${text}">${text}</button>`).join('')}</div><button type="button" id="confirm-reason" class="primary-btn" disabled>확인</button></div></div>`;}
function renderInterventionOpen(){const state=getState(); const app=queryParam('app') || 'Instagram'; const protectedApp=appsToConfigure(state).includes(app); return `<div class="phone"><div style="position:relative;flex:1;min-height:0;overflow:hidden;">${appPreview(app)}${protectedApp ? interventionOverlay() : ''}</div></div>`;}
function mount(){const app=document.getElementById('app'); const page=document.body.dataset.page; if(page==='index'){app.innerHTML=`<div class="card"><h3>페이지 구조</h3><div class="index-links"><a href="${pathTo('onboarding/welcome/')}">온보딩 / welcome</a><a href="${pathTo('onboarding/permissions/')}">온보딩 / permissions</a><a href="${pathTo('onboarding/apps/')}">온보딩 / apps</a><a href="${pathTo('main/settings/')}">메인 / settings</a><a href="${pathTo('main/intervention/')}">메인 / intervention</a></div></div>`; return;}
if(page==='onboarding-welcome') app.innerHTML=phoneFrame(renderWelcome());
if(page==='onboarding-permissions') app.innerHTML=phoneFrame(renderPermissions());
if(page==='onboarding-apps') app.innerHTML=phoneFrame(renderAppsPage());
if(page==='main-settings') app.innerHTML=phoneFrame(renderSettingsList());
if(page==='main-settings-detail') app.innerHTML=phoneFrame(renderSettingsDetail());
if(page==='main-intervention') app.innerHTML=renderInterventionHome();
if(page==='main-intervention-open') app.innerHTML=renderInterventionOpen();
bindEvents();}
function bindEvents(){const page=document.body.dataset.page; const state=getState();
if(page==='onboarding-permissions'){document.querySelectorAll('[data-action="toggle-permission"]').forEach(btn=>{btn.addEventListener('click',()=>{const key=btn.dataset.key; state.permissions[key]=!state.permissions[key]; setState(state); mount();});}); const allBtn=document.querySelector('[data-action="allow-all"]'); if(allBtn){allBtn.addEventListener('click',()=>{const next=!(state.permissions.usage && state.permissions.notifications); state.permissions.usage=next; state.permissions.notifications=next; setState(state); mount();});}}
if(page==='onboarding-apps'){const list=document.getElementById('app-list'); const input=document.getElementById('app-search'); if(list) list.innerHTML=renderAppRows(''); if(input){input.addEventListener('input',e=>{list.innerHTML=renderAppRows(e.target.value || ''); bindEvents();});} document.querySelectorAll('[data-action="toggle-app"]').forEach(btn=>{btn.addEventListener('click',()=>{const appName=btn.dataset.app; if(state.selectedApps.includes(appName)){state.selectedApps=state.selectedApps.filter(v=>v!==appName);} else {state.selectedApps.push(appName);} setState(state); mount();});});}
if(page==='main-settings-detail'){const appName=queryParam('app') || 'Instagram'; ensureAppSchedules(state, appName); document.querySelectorAll('input[type="time"]').forEach(input=>{input.addEventListener('input',e=>{const t=e.target; const id=Number(t.dataset.range); const field=t.dataset.field; const range=state.schedules[appName].find(r=>r.id===id); if(range){range[field]=t.value; setState(state); mount();}});}); const addBtn=document.getElementById('add-range'); if(addBtn){addBtn.addEventListener('click',()=>{state.schedules[appName].push({id:state.nextRangeId,start:'18:00',end:'21:00'}); state.nextRangeId += 1; setState(state); mount();});}}
if(page==='main-intervention-open'){const textarea=document.getElementById('reason-text'); const confirm=document.getElementById('confirm-reason'); const overlay=document.getElementById('overlay'); const close=document.getElementById('close-overlay'); if(textarea && confirm){textarea.addEventListener('input',()=>{confirm.disabled=!textarea.value.trim();});} document.querySelectorAll('[data-chip]').forEach(chip=>{chip.addEventListener('click',()=>{if(textarea) textarea.value=chip.dataset.chip; if(confirm) confirm.disabled=false;});}); if(close && overlay){close.addEventListener('click',()=>overlay.remove());}}
}
document.addEventListener('DOMContentLoaded', mount);
